import React from "react";

import { Rating } from "./Rating";
import { Stack, HStack } from "../Stack";

export default {
  title: "Forms/Rating",
  component: Rating,
  parameters: {
    layout: "padded",
  },
};

export const Basic = () => (
  <Rating defaultValue={3} count={5}>
    <Rating.Control>
      {[1, 2, 3, 4, 5].map((index) => (
        <Rating.Item key={index} index={index}>
          <Rating.ItemIndicator />
        </Rating.Item>
      ))}
    </Rating.Control>
  </Rating>
);

